module top_module(
    input CLK,
    input RST,
    input CLR,
    input LD,
    input [3:0] DATA,
    output reg [4:0] Q
);reg [3:0] decremental_counter;
reg [3:0] async_counter;

always @(posedge CLK) begin
    if (RST) begin
        decremental_counter <= 4'b0000;
    end else begin
        decremental_counter <= decremental_counter + 1;
    end
end

always @(posedge CLK) begin
    if (CLR) begin
        async_counter <= 4'b0000;
    end else if (LD) begin
        async_counter <= DATA;
    end else begin
        async_counter <= async_counter + 1;
    end
end

always @* begin
    Q = decremental_counter + async_counter;
end

endmodule
